1	// COR24 APL Interpreter -- Parser
2	// Right-to-left recursive descent with vector literal stranding.
3	// APL: all operators equal precedence, right-associative.
4	// 2 + 3 * 4  ->  2 + (3 * 4)  ->  14
5	// 1 2 3      ->  3-element vector (adjacent numbers strand)
6	
7	#pragma once
8	
9	// AST node types
10	#define NODE_NUM    0   // integer literal (val = value)
11	#define NODE_BINOP  1   // binary op (val = operator tok type)
12	#define NODE_NEG    2   // monadic negate (right = operand)
13	#define NODE_IDENT  3   // variable reference (val = symbol index)
14	#define NODE_ASSIGN 4   // assignment (val = symbol index, right = expr)
15	#define NODE_VEC    5   // vector literal (val = heap array index)
16	
17	#define AST_MAX 64
18	
19	// AST storage (parallel arrays)
20	int node_type[AST_MAX];
21	int node_val[AST_MAX];
22	int node_left[AST_MAX];
23	int node_right[AST_MAX];
24	int node_count;
25	
26	// Parser state
27	int parse_pos;
28	int parse_err;
29	char *parse_line;   // source line for identifier lookup
30	
31	// Allocate a new AST node
32	int ast_new() {
33	    if (node_count >= AST_MAX) {
34	        parse_err = 1;
35	        return 0;
36	    }
37	    int n = node_count;
38	    node_count++;
39	    node_left[n] = -1;
40	    node_right[n] = -1;
41	    return n;
42	}
43	
44	int ast_num(int val) {
45	    int n = ast_new();
46	    node_type[n] = NODE_NUM;
47	    node_val[n] = val;
48	    return n;
49	}
50	
51	int ast_binop(int op, int left, int right) {
52	    int n = ast_new();
53	    node_type[n] = NODE_BINOP;
54	    node_val[n] = op;
55	    node_left[n] = left;
56	    node_right[n] = right;
57	    return n;
58	}
59	
60	int ast_neg(int operand) {
61	    int n = ast_new();
62	    node_type[n] = NODE_NEG;
63	    node_right[n] = operand;
64	    return n;
65	}
66	
67	int ast_ident(int sym_idx) {
68	    int n = ast_new();
69	    node_type[n] = NODE_IDENT;
70	    node_val[n] = sym_idx;
71	    return n;
72	}
73	
74	int ast_assign(int sym_idx, int expr) {
75	    int n = ast_new();
76	    node_type[n] = NODE_ASSIGN;
77	    node_val[n] = sym_idx;
78	    node_right[n] = expr;
79	    return n;
80	}
81	
82	int ast_vec(int heap_idx) {
83	    int n = ast_new();
84	    node_type[n] = NODE_VEC;
85	    node_val[n] = heap_idx;
86	    return n;
87	}
88	
89	// Temporary buffer for collecting strand elements
90	int strand_buf[64];
91	
92	int is_binop(int ty) {
93	    return ty == TOK_PLUS || ty == TOK_MINUS || ty == TOK_STAR || ty == TOK_SLASH;
94	}
95	
96	// Combined parse function avoids mutual recursion.
97	// mode 0 = expression, mode 1 = value only
98	int parse_node(int mode);
99	
100	int parse_node(int mode) {
101	    if (parse_err) return 0;
102	
103	    int left;
104	    int ty = tok_type[parse_pos];
105	
106	    // -- Parse a value --
107	
108	    if (ty == TOK_NUM) {
109	        left = ast_num(tok_val[parse_pos]);
110	        parse_pos++;
111	
112	        // Stranding: adjacent numbers form a vector (e.g. 1 2 3)
113	        if (tok_type[parse_pos] == TOK_NUM) {
114	            strand_buf[0] = node_val[left];
115	            int count = 1;
116	            while (tok_type[parse_pos] == TOK_NUM && count < 64) {
117	                strand_buf[count] = tok_val[parse_pos];
118	                parse_pos++;
119	                count++;
120	            }
121	            int aidx = arr_vector(count);
122	            if (aidx < 0) { parse_err = 1; return 0; }
123	            int si = 0;
124	            while (si < count) {
125	                arr_set(aidx, si, strand_buf[si]);
126	                si++;
127	            }
128	            left = ast_vec(aidx);
129	        }
130	    } else if (ty == TOK_LPAREN) {
131	        parse_pos++;
132	        left = parse_node(0);
133	        if (parse_err) return 0;
134	        if (tok_type[parse_pos] != TOK_RPAREN) {
135	            parse_err = 1;
136	            return 0;
137	        }
138	        parse_pos++;
139	    } else if (ty == TOK_IDENT) {
140	        int sym_idx = sym_lookup(parse_line, tok_val[parse_pos]);
141	        if (sym_idx < 0) { parse_err = 1; return 0; }
142	        left = ast_ident(sym_idx);
143	        parse_pos++;
144	    } else if (ty == TOK_MINUS) {
145	        // Monadic negate: applies to entire right expression (APL rule)
146	        parse_pos++;
147	        int operand = parse_node(0);
148	        if (parse_err) return 0;
149	        left = ast_neg(operand);
150	    } else {
151	        parse_err = 1;
152	        return 0;
153	    }
154	
155	    // -- If mode 0 (expr) and next is binop, parse right side --
156	
157	    if (mode == 0 && is_binop(tok_type[parse_pos])) {
158	        int op = tok_type[parse_pos];
159	        parse_pos++;
160	        int right = parse_node(0);
161	        if (parse_err) return 0;
162	        return ast_binop(op, left, right);
163	    }
164	
165	    return left;
166	}
167	
168	// Parse the token stream. Returns root node index, or -1 on error.
169	// line is needed for identifier name resolution into the symbol table.
170	int parse(char *line) {
171	    node_count = 0;
172	    parse_pos = 0;
173	    parse_err = 0;
174	    parse_line = line;
175	
176	    // Check for assignment: IDENT <- expr
177	    if (tok_type[0] == TOK_IDENT && tok_type[1] == TOK_ASSIGN) {
178	        int sym_idx = sym_lookup(line, tok_val[0]);
179	        if (sym_idx < 0) { return -1; }
180	        parse_pos = 2;
181	        int expr = parse_node(0);
182	        if (parse_err) return -1;
183	        if (tok_type[parse_pos] != TOK_EOL) return -1;
184	        return ast_assign(sym_idx, expr);
185	    }
